function solve(c, connections, queries) {
    class MinHeap {
        constructor(arr) {
            this.heap = [];
            if (arr !== undefined && arr.length) {
                this.heap = [...arr];
                this.heapify();
            }
        }
        heapify() {
            const n = this.heap.length;
            for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
                this.siftDown(i);
            }
        }
        siftDown(idx) {
            let minIdx = idx;
            const left = 2 * idx + 1;
            const right = 2 * idx + 2;
            const n = this.heap.length;
            if (left < n && this.heap[left] < this.heap[minIdx]) {
                minIdx = left;
            }
            if (right < n && this.heap[right] < this.heap[minIdx]) {
                minIdx = right;
            }
            if (minIdx !== idx) {
                [this.heap[idx], this.heap[minIdx]] = [this.heap[minIdx], this.heap[idx]];
                this.siftDown(minIdx);
            }
        }
        pop() {
            if (this.heap.length === 0) return;
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            if (this.heap.length > 0) {
                this.siftDown(0);
            }
        }
        peek() {
            if (this.heap.length === 0) return -1;
            return this.heap[0];
        }
        size() {
            return this.heap.length;
        }
    }

    let parent = Array.from({ length: c + 1 }, (_, i) => i);
    let rank = new Array(c + 1).fill(0);

    const find = (x) => {
        let root = x;
        while (parent[root] !== root) {
            root = parent[root];
        }
        let curr = x;
        while (curr !== root) {
            const next = parent[curr];
            parent[curr] = root;
            curr = next;
        }
        return root;
    };

    const union = (x, y) => {
        const rx = find(x);
        const ry = find(y);
        if (rx === ry) return;
        if (rank[rx] < rank[ry]) {
            parent[rx] = ry;
        } else if (rank[ry] < rank[rx]) {
            parent[ry] = rx;
        } else {
            parent[ry] = rx;
            rank[rx]++;
        }
    };

    for (const [u, v] of connections) {
        union(u, v);
    }

    const rootArr = new Array(c + 1);
    for (let i = 1; i <= c; i++) {
        rootArr[i] = find(i);
    }

    const compMap = new Map();
    for (let i = 1; i <= c; i++) {
        const r = rootArr[i];
        if (!compMap.has(r)) {
            compMap.set(r, []);
        }
        compMap.get(r).push(i);
    }

    const compHeap = new Map();
    for (const [r, nodes] of compMap) {
        compHeap.set(r, new MinHeap(nodes));
    }

    const online = new Array(c + 1).fill(true);
    const ans = [];

    for (const [type, x] of queries) {
        if (type === 2) {
            if (online[x]) {
                online[x] = false;
            }
        } else if (type === 1) {
            if (online[x]) {
                ans.push(x);
            } else {
                const r = rootArr[x];
                const heap = compHeap.get(r);
                while (heap.size() > 0 && !online[heap.peek()]) {
                    heap.pop();
                }
                if (heap.size() === 0) {
                    ans.push(-1);
                } else {
                    ans.push(heap.peek());
                }
            }
        }
    }

    return ans;
}
